import React from 'react';
import { useFormik } from 'formik';
import './App.css'; 
import { BrowserRouter, Route, Routes, useNavigate } from 'react-router-dom';
import Main from './main';

const SignupForm = () => {
  const navigate = useNavigate();

  const formik = useFormik({
    initialValues: {
      Name: '',
      Address: '',
      mobile: '',
      city: '',
      district: '',
      census: '',
      feeder:  '',
    },
    onSubmit: (values) => {
      navigate('/main');
    },
  });


  // const handleClick = (e) => {
  //   navigate('/main');
  // };  

  return (
    <div className="form-page">
      <h2>Enter Forms Details</h2>
    <form onSubmit={formik.handleSubmit} className='form-container'>

    <div className='input-main'>
      <div className='b1-input'>
      <label htmlFor="Name">Name :</label><br />
      <input  id="Name" name="Name" type="text" onChange={formik.handleChange} value={formik.values.Name} required /><br /><br />

      <label htmlFor="Address">Address :</label><br />
      <input id="Address" name="Address" type="text" onChange={formik.handleChange} value={formik.values.Address} required /><br /><br />

      <label htmlFor="Mobile">Mobile Number :</label><br />
      <input id="mobile" name="mobile" type="text" onChange={formik.handleChange} value={formik.values.mobile} required /><br /><br />

      <label htmlFor="city">City :</label><br />
      <input id="city" name="city" type="text" onChange={formik.handleChange} value={formik.values.city} required /><br /><br />

      <label htmlFor="district">District :</label><br />
      <input id="district" name="district" type="text" onChange={formik.handleChange} value={formik.values.district} required /><br /><br />

      <label htmlFor="census">Census Code :</label><br />
      <input id="census" name="census" type="text" onChange={formik.handleChange} value={formik.values.census} required /><br /><br />

      <label htmlFor="feeder">Feeder Code :</label><br />
      <input id="feeder" name="feeder" type="text" onChange={formik.handleChange} value={formik.values.feeder} required /><br /><br />
    </div>

    <div className='b2-input'>
      <label htmlFor="Name">Name :</label><br />
      <input  id="Name" name="Name" type="text" onChange={formik.handleChange} value={formik.values.Name} required /><br /><br />

      <label htmlFor="Address">Address :</label><br />
      <input id="Address" name="Address" type="text" onChange={formik.handleChange} value={formik.values.Address} required /><br /><br />

      <label htmlFor="Mobile">Mobile Number :</label><br />
      <input id="mobile" name="mobile" type="text" onChange={formik.handleChange} value={formik.values.mobile} required /><br /><br />

      <label htmlFor="city">City :</label><br />
      <input id="city" name="city" type="text" onChange={formik.handleChange} value={formik.values.city} required /><br /><br />

      <label htmlFor="district">District :</label><br />
      <input id="district" name="district" type="text" onChange={formik.handleChange} value={formik.values.district} required /><br /><br />

      <label htmlFor="census">Census Code :</label><br />
      <input id="census" name="census" type="text" onChange={formik.handleChange} value={formik.values.census} required /><br /><br />

      <label htmlFor="feeder">Feeder Code :</label><br />
      <input id="feeder" name="feeder" type="text" onChange={formik.handleChange} value={formik.values.feeder} required /><br /><br />
    </div>
    </div>

   <div className='btn-box'>
      <button style={{backgroundColor:'red', borderRadius:5, color:"white"}} type="submit" >Submit</button>
    </div>
    </form>
    </div>
  );
};

export default function App() {
  return (
    <BrowserRouter>
    <Routes>
      <Route path="/" element={<SignupForm />} />
      <Route path="/main" element={<Main />} />
    </Routes>
    </BrowserRouter>
  );
}
